#include <string>

#include "envoy/http/filter.h"
#include "envoy/registry/registry.h"
#include "envoy/server/filter_config.h"

#include "source/extensions/filters/http/common/factory_base.h"
#include "google/protobuf/empty.pb.h"

namespace Envoy {
namespace Extensions {
namespace HttpFilters {
namespace PassThroughFilter {

/**
 * Config registration for the pass-through filter.
 */
class PassThroughFilterFactory : public Common::FactoryBase<google::protobuf::Empty> {
public:
  PassThroughFilterFactory() : FactoryBase("envoy.filters.http.pass_through") {}

private:
  Http::FilterFactoryCb createFilterFactoryFromProtoTyped(
      const google::protobuf::Empty&, const std::string&,
      Server::Configuration::FactoryContext&) override {
    auto config = std::make_shared<PassThroughFilterConfig>();
    return [config](Http::FilterChainFactoryCallbacks& callbacks) -> void {
      callbacks.addStreamDecoderFilter(std::make_shared<PassThroughFilter>(config));
    };
  }
};

/**
 * Static registration for the pass-through filter. @see RegisterFactory.
 */
REGISTER_FACTORY(PassThroughFilterFactory, Server::Configuration::NamedHttpFilterConfigFactory);

} // namespace PassThroughFilter
} // namespace HttpFilters
} // namespace Extensions
} // namespace Envoy

